 1	import * as React from 'react';
 2	import { RequestSizeInput } from '../../common/request-size-input';
 3	import { useTranslation } from 'react-i18next';
 4	import { FormikValues, useField, useFormikContext } from 'formik';
 5	import {
 6	  FormGroup,
 7	  FormHelperText,
 8	  HelperText,
 9	  HelperTextItem,
10	} from '@patternfly/react-core';
11	
12	const PipelineTimeoutSection = () => {
13	  const { t } = useTranslation('plugin__pipelines-console-plugin');
14	  const [, { touched, error }] = useField<string | string[]>(
15	    'timeouts.timeValue',
16	  );
17	  const [timeoutUnit, setTimeoutUnit] = React.useState('m');
18	  const [timeoutValue, setTimeoutValue] = React.useState(60);
19	  const { setFieldValue, setFieldTouched } = useFormikContext<FormikValues>();
20	  const isValid = !(touched && !!error);
21	  const errorMessage = !isValid ? error : '';
22	  const handleTimeOutChange = (timeoutValue) => {
23	    const { value, unit } = timeoutValue;
24	    setTimeoutValue(value);
25	    setTimeoutUnit(unit);
26	    setFieldValue('timeouts.timeValue', value);
27	    setFieldTouched('timeouts.timeValue', true);
28	    setFieldValue('timeouts.timeUnit', unit);
29	  };
30	  const dropdownUnits = React.useMemo(
31	    () => ({
32	      h: t('Hr'),
33	      m: t('Min'),
34	      s: t('Sec'),
35	    }),
36	    [t],
37	  );
38	  return (
39	    <FormGroup label={t('Timeouts')}>
40	      <RequestSizeInput
41	        name="timeouts.time"
42	        onChange={handleTimeOutChange}
43	        defaultRequestSizeUnit={timeoutUnit}
44	        defaultRequestSizeValue={timeoutValue}
45	        dropdownUnits={dropdownUnits}
46	        describedBy="timeout-help"
47	        inputID="timeout-input"
48	        data-test-id="timeout-input"
49	        minValue={0}
50	        allowDecimalValue
51	      />
52	      <FormHelperText>
53	        <HelperText>
54	          {!isValid ? (
55	            <HelperTextItem variant="error">{errorMessage}</HelperTextItem>
56	          ) : (
57	            <HelperTextItem>{t('Timeout for the pipeline')}</HelperTextItem>
58	          )}
59	        </HelperText>
60	      </FormHelperText>
61	    </FormGroup>
62	  );
63	};
64	
65	export default PipelineTimeoutSection;

